export const logger = winston.createLogger({
  level: process.env.LOG_LEVEL ?? "info",
  defaultMeta: { service: "ai-novel-server" },
  transports: [
    fileRotateTransport,
    errorFileRotateTransport,
    new winston.transports.Console({ ... }),
  ],
});

function logServerError(req: Request, error: unknown): void {
  console.error(`[error] ${req.method} ${req.originalUrl}`, error);
}

app.use(morgan((tokens, req, res) => {
  const method = tokens.method(req, res) ?? "-";
  const url = tokens.url(req, res) ?? "-";
  const status = tokens.status(req, res) ?? "-";
  const responseTime = tokens["response-time"](req, res) ?? "0";
  const contentLength = tokens.res(req, res, "content-length") ?? "0";
  return `${method} ${url} ${status} ${responseTime} ms - ${contentLength}`;
}));

catch (err) {
  console.error(`[EventBus] handler error for ${event.type}:`, err);
}

router.get("/", (_req, res) => {
  const response: ApiResponse<{ status: string; timestamp: string }> = {
    success: true,
    data: {
      status: "ok",
      timestamp: new Date().toISOString(),
    },
  };
  res.status(200).json(response);
});

function shouldLogLLMRequests(): boolean {
  const raw = process.env.LLM_DEBUG_LOG?.trim().toLowerCase();
  if (raw && LOG_FALSE_VALUES.has(raw)) return false;
  if (raw && LOG_TRUE_VALUES.has(raw)) return true;
  return process.env.NODE_ENV !== "production";
}
